module gated_flip_flop(  
    input clk,  
    input rst,  
    input clk_en,  
    input d,  
    output reg q  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge rst) begin  
        if (rst)  
            q <= 1'b0;  
        else if (clk_en)  
            q <= d;  
    end  
endmodule
